parameters.responseBody:
={{ (function() {
  const order = $('Fetch Order by Token').first().json;
  let items = [];
  try { items = typeof order.items === 'string' ? JSON.parse(order.items) : (order.items || []); } catch(e) {}
  const token = $('Webhook (GET)').first().json.query.token;

  // ── Service vs product framing ──
  const isBooking = order.delivery_type === 'appointment';
  const pageTitle     = isBooking ? 'Confirm Booking'          : 'Confirm Order';
  const sectionLabel  = isBooking ? 'Booking Summary'          : 'Order Summary';
  const submitLabel   = isBooking ? 'Confirm & Notify Customer': 'Confirm & Notify Customer';
  const successMsg    = isBooking
    ? 'Booking confirmed. Customer has been notified.'
    : 'Order confirmed. Customer has been notified with your payment details.';
  const warningMsg    = isBooking
    ? '⚠️ Confirm your password to confirm this booking. The customer will be notified immediately.'
    : '⚠️ Enter the bank account you want to receive payment to, then confirm with your MySquad password. The customer will receive these details immediately.';
  const showPayment   = !isBooking;

  // ── Appointment details (service bookings) ──
  let appointmentHtml = '';
  if (isBooking && order.appointment_datetime) {
    try {
      const dt = new Date(order.appointment_datetime);
      const formatted = dt.toLocaleString('en-NG', {
        timeZone: 'Africa/Lagos',
        weekday: 'short', month: 'short', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
      });
      appointmentHtml = '<li style="color:#F13A01;font-weight:600">📅 ' + formatted + '</li>';
      if (order.appointment_location) {
        appointmentHtml += '<li>📍 ' + order.appointment_location + '</li>';
      }
    } catch(e) {}
  }

  // ── Items list ──
  const itemsHtml = items.map(i =>
    '<li>' + (i.quantity||1) + 'x ' + i.name +
    (i.unit_price ? ' — ₦' + Number(i.unit_price).toLocaleString() : '') +
    '</li>'
  ).join('');

  // ── Payment fields HTML (only for product orders) ──
  const paymentFieldsHtml = showPayment ? `
    <label>Bank Name</label>
    <input type="text" id="bankName" placeholder="e.g. GTBank" autocomplete="off" autocorrect="off">
    <label>Account Number</label>
    <input type="text" id="acctNo" placeholder="10-digit NUBAN" maxlength="11" inputmode="numeric" autocomplete="off" oninput="this.value=this.value.replace(/\\D/g,'').slice(0,10)">
    <label>Account Name</label>
    <input type="text" id="acctName" placeholder="As it appears on your account" autocomplete="off" autocorrect="off">
  ` : '';

  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${pageTitle} — ${order.order_number}</title>
<style>
:root {
  --accent: #F13A01;
  --accent-dark: #C42D00;
  --accent-pale: #FFF5F2;
  --text: #111;
  --text-muted: #666;
  --border: #e0e0e0;
  --bg: #F5F4F2;
  --surface: #fff;
  --radius: 16px;
  --radius-sm: 10px;
  --radius-xs: 8px;
}
* { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: var(--bg);
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px;
}
.card {
  background: var(--surface);
  border-radius: var(--radius);
  padding: 32px 24px;
  max-width: 420px;
  width: 100%;
  box-shadow: 0 4px 24px rgba(0,0,0,0.08);
}
.logo-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 20px;
}
.logo-dot {
  width: 10px; height: 10px;
  border-radius: 50%;
  background: var(--accent);
  flex-shrink: 0;
}
.biz-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  letter-spacing: 0.2px;
}
h1 {
  font-size: 22px;
  font-weight: 800;
  color: var(--text);
  margin-bottom: 4px;
  line-height: 1.2;
}
.order-ref {
  font-size: 13px;
  color: var(--accent);
  font-weight: 700;
  margin-bottom: 22px;
  letter-spacing: 0.5px;
}
.section-title {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--accent);
  letter-spacing: 0.8px;
  margin-bottom: 8px;
}
.summary-box {
  background: var(--accent-pale);
  border: 1px solid rgba(241,58,1,.12);
  border-radius: var(--radius-sm);
  padding: 14px 16px;
  margin-bottom: 22px;
}
.summary-box ul { list-style: none; }
.summary-box li {
  font-size: 14px;
  color: #333;
  padding: 4px 0;
  border-bottom: 1px solid rgba(241,58,1,.08);
}
.summary-box li:last-child { border-bottom: none; }
.total {
  font-size: 16px;
  font-weight: 800;
  color: var(--text);
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1.5px solid rgba(241,58,1,.15);
}
.warning {
  background: #fff8e1;
  border-left: 3px solid #f59e0b;
  border-radius: var(--radius-xs);
  padding: 12px 14px;
  font-size: 13px;
  color: #7a5c00;
  margin-bottom: 22px;
  line-height: 1.6;
}
label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: #444;
  margin-bottom: 6px;
}
input {
  width: 100%;
  padding: 12px 14px;
  border: 1.5px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 15px;
  color: var(--text);
  outline: none;
  transition: border-color 0.18s, box-shadow 0.18s;
  margin-bottom: 16px;
  background: #fafaf8;
  -webkit-appearance: none;
  font-family: inherit;
}
input:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(241,58,1,.10);
  background: #fff;
}
input[type=password] { letter-spacing: 2px; }
.divider { border: none; border-top: 1px solid #eee; margin: 20px 0; }
.error-msg {
  color: #c00;
  font-size: 13px;
  margin-top: -10px;
  margin-bottom: 14px;
  display: none;
  align-items: center;
  gap: 6px;
}
.error-msg.show { display: flex; }
button {
  width: 100%;
  padding: 15px;
  background: var(--accent);
  color: #fff;
  font-size: 16px;
  font-weight: 700;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background 0.18s, box-shadow 0.18s, transform 0.1s;
  font-family: inherit;
  box-shadow: 0 2px 12px rgba(241,58,1,.3);
}
button:hover { background: var(--accent-dark); box-shadow: 0 4px 16px rgba(241,58,1,.4); transform: translateY(-1px); }
button:active { transform: translateY(0); }
button:disabled { background: #aaa; cursor: not-allowed; box-shadow: none; transform: none; }
.success-area {
  text-align: center;
  display: none;
  padding: 20px 0 8px;
}
.success-icon { font-size: 52px; margin-bottom: 16px; }
.success-title { font-size: 22px; font-weight: 800; color: var(--text); margin-bottom: 10px; }
.success-sub { color: var(--text-muted); font-size: 15px; line-height: 1.6; }
@media (max-width: 480px) {
  .card { padding: 24px 18px; }
  h1 { font-size: 20px; }
}
</style>
</head>
<body>
<div class="card">

  <div class="logo-bar">
    <div class="logo-dot"></div>
    <div class="biz-name">${order.business_name}</div>
  </div>

  <h1>${pageTitle}</h1>
  <div class="order-ref">${order.order_number}</div>

  <div class="section-title">${sectionLabel}</div>
  <div class="summary-box">
    <ul>
      ${appointmentHtml}
      ${itemsHtml || '<li>No items found</li>'}
    </ul>
    <div class="total">Total: ₦${Number(order.total_amount).toLocaleString()}</div>
  </div>

  <div class="warning">${warningMsg}</div>

  <div id="formArea">
    ${paymentFieldsHtml}

    <label>Your Password</label>
    <input type="password" id="password" placeholder="Enter your MySquad password" autocomplete="current-password">

    <div class="error-msg" id="errorMsg">⚠ <span id="errorText"></span></div>

    <button id="submitBtn" onclick="submitForm()">${submitLabel}</button>
  </div>

  <div class="success-area" id="successArea">
    <div class="success-icon">✅</div>
    <div class="success-title">Done!</div>
    <p class="success-sub">${successMsg}</p>
  </div>

</div>
<script>
var IS_BOOKING = ${isBooking ? 'true' : 'false'};

async function submitForm() {
  var btn = document.getElementById('submitBtn');
  var errWrap = document.getElementById('errorMsg');
  var errText = document.getElementById('errorText');
  errWrap.classList.remove('show');

  var password = document.getElementById('password').value;
  var bankName = '', acctNoClean = '', acctName = '';

  if (!IS_BOOKING) {
    bankName    = document.getElementById('bankName').value.trim();
    var acctNoRaw = document.getElementById('acctNo').value;
    acctNoClean = acctNoRaw.replace(/\\D/g, '');
    acctName    = document.getElementById('acctName').value.trim();

    if (!bankName || !acctNoClean || !acctName || !password) {
      errText.textContent = 'Please fill in all fields.';
      errWrap.classList.add('show');
      return;
    }
    if (acctNoClean.length !== 10) {
      errText.textContent = 'Account number must be exactly 10 digits.';
      errWrap.classList.add('show');
      return;
    }
  } else {
    if (!password) {
      errText.textContent = 'Please enter your password to confirm.';
      errWrap.classList.add('show');
      return;
    }
  }

  btn.disabled = true;
  btn.textContent = 'Confirming...';

  try {
    var res = await fetch('/webhook/order-confirm-submit', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        token: '${token}',
        bankName: bankName,
        acctNo: acctNoClean,
        acctName: acctName,
        password: password
      })
    });
    var data = await res.json();

    if (data.success) {
      document.getElementById('formArea').style.display = 'none';
      document.getElementById('successArea').style.display = 'block';
    } else {
      errText.textContent = data.message || 'Something went wrong. Please try again.';
      errWrap.classList.add('show');
      btn.disabled = false;
      btn.textContent = '${submitLabel}';
    }
  } catch(e) {
    errText.textContent = 'Network error. Please try again.';
    errWrap.classList.add('show');
    btn.disabled = false;
    btn.textContent = '${submitLabel}';
  }
}
</script>
</body>
</html>`;
})() }}

